#include<bits/stdc++.h>
using namespace std;
int n;
class tree {
    public:
	int val, left, right;
} a[100001];

void dfsq(int x) {
	if (x == 0) return;
	cout << a[x].val << " ";
	dfsq(a[x].left);
	dfsq(a[x].right);
}
void dfsz(int x) {
	if (x == 0) return;
	dfsz(a[x].left);
	cout << a[x].val << " ";
	dfsz(a[x].right);
}
void dfsh(int x) {
	if (x == 0) return;

	dfsh(a[x].left);
	dfsh(a[x].right);
	cout << a[x].val << " ";
}
int main() {
	cin >> n;
	for (int i = 1; i <= n; i++) {
		cin >> a[i].left >> a[i].right;
		a[i].val = i;
	}
	dfsq(1);
	cout << endl;
	dfsz(1);
	cout << endl;
	dfsh(1);
	return 0;
}
